  els.quizModeBtn.addEventListener('click', () => setStatePatch({ mode: 'quiz' })); els.flashModeBtn.addEventListener('click', () => setStatePatch({ mode: 'flashcard' })); els.shuffleBtn.addEventListener('click', shuffleCurrentView); els.resetViewBtn.addEventListener('click', resetView); els.exportProgressBtn.addEventListener('click', exportProgress); els.importProgressBtn.addEventListener('click', () => els.importProgressFile.click()); els.importProgressFile.addEventListener('change', e => importProgress(e.target.files[0])); els.resetAllBtn.addEventListener('click', resetAll);
  document.addEventListener('keydown', e => { const tag = e.target?.tagName?.toLowerCase(); const typing = tag === 'input' || tag === 'select' || tag === 'textarea'; if (typing) { if (e.key === 'Escape') e.target.blur(); return; } const q = currentQuestion(); if (e.key === '/' && !typing) { e.preventDefault(); els.searchInput.focus(); return; } if (!q) return; const key = e.key.toLowerCase(); if (key === 'enter' || e.code === 'Space') { if (state.resolved || state.mode === 'flashcard') { e.preventDefault(); nextQuestion(); } return; } if (key === 'arrowright' || key === 'n') { e.preventDefault(); nextQuestion(); return; } if (key === 'arrowleft' || key === 'p') { e.preventDefault(); prevQuestion(); return; } if (key === 'r') { e.preventDefault(); retryQuestion(); return; } if (key === 'f') { e.preventDefault(); toggleMark(); return; } if (key === 'm') { e.preventDefault(); markLearned(); return; } const byLetter = LETTERS.indexOf(e.key.toUpperCase()); const byNumber = /^[1-9]$/.test(e.key) ? Number(e.key)-1 : -1; const index = byLetter >= 0 ? byLetter : byNumber; if (index >= 0 && index < q.options.length) { e.preventDefault(); selectOption(index); } });
